changeSet.sql:
-- Mileage history: timeline queries ordered by date
CREATE INDEX IF NOT EXISTS idx_vehicle_mileage_vehicle_id
    ON vehicle_mileage_history (vehicle_id);
CREATE INDEX IF NOT EXISTS idx_vehicle_mileage_vehicle_date
    ON vehicle_mileage_history (vehicle_id, recorded_date DESC);

-- MOT history: timeline queries ordered by test date
CREATE INDEX IF NOT EXISTS idx_vehicle_mot_vehicle_id
    ON vehicle_mot_history (vehicle_id);
CREATE INDEX IF NOT EXISTS idx_vehicle_mot_vehicle_date
    ON vehicle_mot_history (vehicle_id, test_date DESC);

-- Ownership history: timeline queries ordered by start date
CREATE INDEX IF NOT EXISTS idx_vehicle_ownership_vehicle_id
    ON vehicle_ownership_history (vehicle_id);
CREATE INDEX IF NOT EXISTS idx_vehicle_ownership_vehicle_date
    ON vehicle_ownership_history (vehicle_id, ownership_start DESC);

-- Valuation history: timeline queries ordered by valuation date
CREATE INDEX IF NOT EXISTS idx_vehicle_valuation_vehicle_id
    ON vehicle_valuation_history (vehicle_id);
CREATE INDEX IF NOT EXISTS idx_vehicle_valuation_vehicle_date
    ON vehicle_valuation_history (vehicle_id, valuation_date DESC);
